'use client';

import { motion } from 'framer-motion';
import { gsap } from '@/lib/animations/gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { useRef, useEffect } from 'react';
import { Card } from '@/components/ui/card';

const education = [
  {
    degree: 'Master of Computer Science',
    institution: 'Tech University',
    year: '2019',
    description: 'Specialized in Web Technologies and Distributed Systems.',
  },
  {
    degree: 'Bachelor of Software Engineering',
    institution: 'State University',
    year: '2017',
    description: 'Focus on software development methodologies and algorithms.',
  },
];

export default function Education() {
  const sectionRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!sectionRef.current) return;
    gsap.fromTo(
      sectionRef.current.querySelectorAll('.edu-item'),
      { y: 50, opacity: 0 },
      {
        y: 0,
        opacity: 1,
        stagger: 0.3,
        duration: 1,
        scrollTrigger: { trigger: sectionRef.current, start: 'top 75%' },
      }
    );
  }, []);

  return (
    <section id="education" ref={sectionRef} className="py-20 md:py-32">
      <div className="container mx-auto px-4">
        <motion.h2 initial={{ opacity: 0 }} whileInView={{ opacity: 1 }} className="edu-item text-3xl md:text-4xl font-bold text-center mb-12 gradient-text">
          Education
        </motion.h2>
        <div className="max-w-3xl mx-auto space-y-6">
          {education.map((edu, index) => (
            <Card key={index} className="edu-item p-6 glass">
              <div className="flex flex-col md:flex-row md:items-center justify-between">
                <div>
                  <h3 className="text-xl font-semibold">{edu.degree}</h3>
                  <p className="text-primary">{edu.institution}</p>
                </div>
                <span className="text-muted-foreground mt-2 md:mt-0">{edu.year}</span>
              </div>
              <p className="text-muted-foreground mt-4">{edu.description}</p>
            </Card>
          ))}
        </div>
      </div>
    </section>
  );
}
