'use client';

import { useEffect, useRef } from 'react';
import { gsap } from '@/lib/animations/gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { motion } from 'framer-motion';
import Image from 'next/image';
import { Button } from '@/components/ui/button';
import { useGlobalStore } from '@/lib/store/useGlobalStore';

const floatingIcons = [
  { name: 'Node.js', src: '/images/node.svg', width: 60, height: 60 },
  { name: 'TypeScript', src: '/images/ts.svg', width: 50, height: 50 },
  { name: 'GraphQL', src: '/images/graphql.svg', width: 55, height: 55 },
  { name: 'AI', src: '/images/ai.svg', width: 45, height: 45 },
];

export default function Hero() {
  const heroRef = useRef<HTMLDivElement>(null);
  const textRef = useRef<HTMLDivElement>(null);
  const imageRef = useRef<HTMLDivElement>(null);
  const floatingRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    if (!textRef.current) return;
    const tl = gsap.timeline({ delay: 0.5 });
    tl.fromTo(
      textRef.current.querySelectorAll('.hero-text-item'),
      { y: 50, opacity: 0 },
      { y: 0, opacity: 1, stagger: 0.15, duration: 0.8 }
    );
  }, []);

  useEffect(() => {
    floatingRefs.current.forEach((ref, index) => {
      if (!ref) return;
      gsap.to(ref, {
        y: 'random(-20, 20)',
        x: 'random(-15, 15)',
        rotation: 'random(-10, 10)',
        duration: 'random(3, 5)',
        repeat: -1,
        yoyo: true,
        ease: 'sine.inOut',
        delay: index * 0.3,
      });
    });
  }, []);

  useEffect(() => {
    if (!imageRef.current || !heroRef.current) return;
    ScrollTrigger.create({
      trigger: heroRef.current,
      start: 'top top',
      end: 'bottom top',
      scrub: true,
      onUpdate: (self) => {
        gsap.to(imageRef.current, { y: self.progress * 100, duration: 0.1 });
      },
    });
  }, []);

  return (
    <section ref={heroRef} className="relative min-h-screen flex items-center justify-center overflow-hidden py-20">
      {floatingIcons.map((icon, index) => (
        <div
          key={icon.name}
          ref={(el) => { floatingRefs.current[index] = el; }}
          className={`absolute opacity-70 hover:opacity-100 transition-opacity ${
            index === 0 ? 'top-10 left-5 md:top-16 md:left-10' :
            index === 1 ? 'top-1/4 left-1/3 md:top-1/4 md:left-1/2' :
            index === 2 ? 'top-1/2 left-2/3 md:top-1/2 md:left-2/3' :
            'top-3/4 left-1/4 md:top-3/4 md:left-1/4'
          }`}
        >
          <Image src={icon.src} alt={icon.name} width={icon.width} height={icon.height} className="w-auto h-auto" />
        </div>
      ))}

      <div className="container mx-auto px-4 z-10 flex flex-col md:flex-row items-center gap-12">
        <div ref={textRef} className="flex-1 text-center md:text-left">
          <motion.h1 initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-4xl md:text-6xl font-bold mb-4">
            <span className="hero-text-item bg-gradient-to-r from-primary to-secondary bg-clip-text text-transparent">
              Hi, I'm [Your Name]
            </span>
          </motion.h1>
          <p className="hero-text-item text-xl md:text-2xl text-muted-foreground mb-6">Full Stack Developer</p>
          <p className="hero-text-item text-lg text-muted-foreground mb-8 max-w-lg">
            Building performant, scalable web applications with modern technologies.
          </p>
          <div className="hero-text-item flex gap-4 justify-center md:justify-start">
            <Button size="lg" asChild>
              <a href="#projects">View Projects</a>
            </Button>
            <Button size="lg" variant="outline" asChild>
              <a href="#contact">Contact Me</a>
            </Button>
          </div>
        </div>

        <div ref={imageRef} className="flex-1 relative w-full max-w-md aspect-square">
          <div className="relative w-full h-full rounded-full overflow-hidden border-4 border-primary/20 shadow-xl">
            <Image src="/images/profile.jpg" alt="Profile" fill className="object-cover" priority />
          </div>
        </div>
      </div>
    </section>
  );
}
